package com.flowmind.common.web;import com.flowmind.common.security.AuthInterceptor;import org.springframework.stereotype.Component;import org.springframework.web.servlet.config.annotation.CorsRegistry;import org.springframework.web.servlet.config.annotation.InterceptorRegistry;import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;@Component public class WebMvcConfig implements WebMvcConfigurer{private final AuthInterceptor authInterceptor;public WebMvcConfig(AuthInterceptor authInterceptor){this.authInterceptor=authInterceptor;}@Override public void addCorsMappings(CorsRegistry registry){registry.addMapping("/**").allowedOriginPatterns("*").allowedMethods("GET","POST","PUT","DELETE","OPTIONS").allowedHeaders("*").allowCredentials(false).maxAge(3600);}@Override public void addInterceptors(InterceptorRegistry registry){registry.addInterceptor(authInterceptor).addPathPatterns("/api/**");}}
